#include <stdio.h>
#include <stdlib.h>
#include <string.h>

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    const int MAXV = 100000 + 5;
    int *left = (int*)calloc(MAXV, sizeof(int));
    int *right = (int*)calloc(MAXV, sizeof(int));
    int *isChild = (int*)calloc(MAXV, sizeof(int));
    while (T--) {
        int N; scanf("%d", &N);
        memset(left, 0, MAXV * sizeof(int));
        memset(right, 0, MAXV * sizeof(int));
        memset(isChild, 0, MAXV * sizeof(int));
        int maxNode = 0;
        for (int i = 0; i < N-1; ++i) {
            int p, c; char dir;
            scanf("%d %d %c", &p, &c, &dir);
            if (dir == 'L') left[p] = c; else right[p] = c;
            isChild[c] = 1;
            if (p > maxNode) maxNode = p;
            if (c > maxNode) maxNode = c;
        }
        int root = -1;
        for (int i = 1; i <= maxNode; ++i) {
            if ((left[i] || right[i] || isChild[i]) && !isChild[i]) { root = i; break; }
        }
        int *stack = (int*)malloc((N+5) * sizeof(int));
        int top = -1;
        stack[++top] = root;
        int first = 1;
        while (top >= 0) {
            int node = stack[top--];
            if (first) { printf("%d", node); first = 0; }
            else printf(" %d", node);
            if (right[node]) stack[++top] = right[node];
            if (left[node])  stack[++top] = left[node];
        }
        printf("\n");
        free(stack);
    }
    free(left); free(right); free(isChild);
    return 0;
}

